## IO correctness ----
test_that("distribution specs describe user-facing likelihood families", {
  #' @description Test that normal returns a FIMS distribution specification.
  normal_spec <- normal(mean = 0, sd = 2)
  expect_s3_class(normal_spec, "fims_distribution_spec")
  expect_equal(normal_spec[["family"]], "normal")
  expect_equal(normal_spec[["backend"]], "DnormDistribution")
  expect_equal(normal_spec[["args"]][["mean"]], 0)
  expect_equal(normal_spec[["args"]][["sd"]], 2)

  #' @description Test that legacy family constructors also carry FIMS distribution spec metadata.
  lognormal_spec <- lognormal(link = "log")
  expect_s3_class(lognormal_spec, "fims_distribution_spec")
  expect_s3_class(lognormal_spec, "family")
  expect_equal(lognormal_spec[["family"]], "lognormal")
  expect_equal(lognormal_spec[["fims_spec"]][["backend"]], "DlnormDistribution")

  multinomial_spec <- multinomial()
  expect_s3_class(multinomial_spec, "fims_distribution_spec")
  expect_s3_class(multinomial_spec, "family")
  expect_equal(multinomial_spec[["family"]], "multinomial")
  expect_equal(
    multinomial_spec[["fims_spec"]][["backend"]],
    "DmultinomDistribution"
  )
})

test_that("role specs describe priors, random effects, and fixed effects", {
  #' @description Test that prior stores a value and distribution without creating Rcpp objects.
  prior_spec <- prior(log(1000), normal(mean = 0, sd = 10))
  expect_s3_class(prior_spec, "fims_role_spec")
  expect_equal(prior_spec[["role"]], "prior")
  expect_equal(prior_spec[["value"]], log(1000))
  expect_s3_class(prior_spec[["distribution"]], "fims_distribution_spec")

  #' @description Test that random effect stores a distribution without requiring IDs.
  random_effect_spec <- random_effect(normal(sd = 0.4))
  expect_s3_class(random_effect_spec, "fims_role_spec")
  expect_equal(random_effect_spec[["role"]], "random_effect")
  expect_s3_class(
    random_effect_spec[["distribution"]],
    "fims_distribution_spec"
  )

  #' @description Test that fixed effect stores fixed numeric values.
  fixed_effect_spec <- fixed_effect(c(1, 2, 3))
  expect_s3_class(fixed_effect_spec, "fims_role_spec")
  expect_equal(fixed_effect_spec[["role"]], "fixed_effect")
  expect_equal(fixed_effect_spec[["value"]], c(1, 2, 3))
})

test_that("observation specs describe data likelihoods without Rcpp links", {
  #' @description Test that landings observations store fleet, data, and distribution specs.
  landings_spec <- observe_landings(
    fleet = "fishery",
    data = c(100, 110),
    distribution = lognormal(sd = 0.2)
  )
  expect_s3_class(landings_spec, "fims_observation_spec")
  expect_equal(landings_spec[["data_type"]], "landings")
  expect_equal(landings_spec[["fleet"]], "fishery")
  expect_equal(landings_spec[["data"]], c(100, 110))
  expect_s3_class(
    landings_spec[["distribution"]],
    "fims_distribution_spec"
  )

  #' @description Test that index observations accept normal distribution specs.
  index_spec <- observe_index(
    fleet = "survey",
    data = c(10, 9, 8),
    distribution = normal(sd = 0.3)
  )
  expect_s3_class(index_spec, "fims_observation_spec")
  expect_equal(index_spec[["data_type"]], "index")
  expect_equal(index_spec[["distribution"]][["family"]], "normal")

  #' @description Test that composition observations store matrix-like data.
  age_comp <- matrix(c(10, 20, 30, 15, 20, 25), nrow = 2, byrow = TRUE)
  age_comp_spec <- observe_age_comp(fleet = "fishery", data = age_comp)
  expect_s3_class(age_comp_spec, "fims_observation_spec")
  expect_equal(age_comp_spec[["data_type"]], "age_comp")
  expect_equal(age_comp_spec[["data"]], age_comp)

  length_comp_spec <- observe_length_comp(
    fleet = "fishery",
    data = age_comp,
    distribution = multinomial()
  )
  expect_s3_class(length_comp_spec, "fims_observation_spec")
  expect_equal(length_comp_spec[["data_type"]], "length_comp")
})

test_that("component specs describe the CatchAtAge model graph", {
  #' @description Test that component specs store backend targets and role specs.
  selectivity <- logistic_selectivity(a50 = 4, slope = fixed_effect(1.5))
  expect_s3_class(selectivity, "fims_component_spec")
  expect_equal(selectivity[["component"]], "logistic_selectivity")
  expect_equal(selectivity[["backend"]], "LogisticSelectivity")
  expect_equal(selectivity[["a50"]][["role"]], "fixed_effect")
  expect_equal(selectivity[["slope"]][["role"]], "fixed_effect")

  maturity <- logistic_maturity(a50 = 3, slope = 1.1)
  expect_s3_class(maturity, "fims_component_spec")
  expect_equal(maturity[["component"]], "logistic_maturity")

  growth <- ewaa_growth(ages = 1:4, weights = c(0.2, 0.5, 0.9, 1.1))
  expect_s3_class(growth, "fims_component_spec")
  expect_equal(growth[["component"]], "ewaa_growth")

  recruitment <- beverton_holt(
    log_rzero = prior(log(1000), normal(sd = 10)),
    steepness = fixed_effect(0.75),
    deviations = random_effect(normal(sd = 0.4))
  )
  expect_s3_class(recruitment, "fims_component_spec")
  expect_equal(recruitment[["component"]], "beverton_holt")
  expect_equal(recruitment[["deviations"]][["role"]], "random_effect")

  fleet_spec <- fleet(
    name = "fishery",
    selectivity = selectivity,
    fishing_mortality = fixed_effect(rep(log(0.1), 3))
  )
  expect_s3_class(fleet_spec, "fims_component_spec")
  expect_equal(fleet_spec[["component"]], "fleet")
  expect_equal(fleet_spec[["name"]], "fishery")

  population_spec <- population(
    name = "stock",
    ages = 1:4,
    years = 2020:2022,
    growth = growth,
    maturity = maturity,
    recruitment = recruitment
  )
  expect_s3_class(population_spec, "fims_component_spec")
  expect_equal(population_spec[["component"]], "population")

  model_spec <- catch_at_age(
    population = population_spec,
    fleets = list(fleet_spec),
    observations = list(
      observe_landings("fishery", c(100, 110, 105), lognormal(sd = 0.2)),
      observe_age_comp("fishery", matrix(1:12, nrow = 3), multinomial())
    )
  )
  expect_s3_class(model_spec, "fims_model_spec")
  expect_equal(model_spec[["model"]], "catch_at_age")
  expect_equal(model_spec[["backend"]], "CatchAtAge")
  expect_equal(model_spec[["likelihood"]], "terms")
  expect_length(model_spec[["fleets"]], 1L)
  expect_length(model_spec[["observations"]], 2L)
})

## Edge handling ----
test_that("likelihood specs validate simple edge cases", {
  #' @description Test that normal rejects non-positive standard deviations.
  expect_error(normal(sd = 0), regexp = "`sd` must be greater than 0")
  expect_error(normal(sd = -1), regexp = "`sd` must be greater than 0")

  #' @description Test that role specs reject missing numeric values.
  expect_error(fixed_effect(NA_real_), regexp = "`value` must be a numeric")
  expect_error(prior(NA_real_, normal()), regexp = "`value` must be a numeric")

  #' @description Test that observation specs reject missing data and fleet names.
  expect_error(
    observe_landings(fleet = "", data = 1),
    regexp = "`fleet` must be a non-empty character scalar"
  )
  expect_error(
    observe_landings(fleet = "fishery", data = NULL),
    regexp = "`data` must not be NULL"
  )

  #' @description Test that model specs validate required names and data.
  expect_error(
    fleet(name = "", selectivity = logistic_selectivity(4, 1)),
    regexp = "`name` must be a non-empty character scalar"
  )
  expect_error(
    ewaa_growth(ages = NA_real_, weights = 1),
    regexp = "`ages` must be a numeric"
  )
})

## Error handling ----
test_that("role specs require distribution specifications", {
  #' @description Test that prior and random effect roles require FIMS distribution specs.
  expect_error(
    prior(1, "normal"),
    regexp = "`distribution` must be a FIMS distribution specification"
  )
  expect_error(
    random_effect(stats::gaussian()),
    regexp = "`distribution` must be a FIMS distribution specification"
  )
})

test_that("observation specs validate compatible distribution families", {
  #' @description Test that observation specs reject incompatible distribution families.
  expect_error(
    observe_landings("fishery", data = 1:3, distribution = multinomial()),
    regexp = "is not supported for `landings` observations"
  )
  expect_error(
    observe_age_comp("fishery", data = matrix(1:4, nrow = 1), distribution = normal()),
    regexp = "is not supported for `age_comp` observations"
  )
})

test_that("component specs validate compatible nested specs", {
  #' @description Test that model component specs reject incompatible nested specs.
  expect_error(
    fleet("fishery", selectivity = logistic_maturity(3, 1)),
    regexp = "`selectivity` must be a selectivity component spec"
  )
  expect_error(
    beverton_holt(
      log_rzero = 1,
      steepness = 0.75,
      deviations = fixed_effect(0)
    ),
    regexp = "`deviations` must be a random effect spec"
  )
  expect_error(
    population(
      name = "stock",
      ages = 1:3,
      years = 2020:2022,
      growth = logistic_selectivity(4, 1),
      maturity = logistic_maturity(3, 1),
      recruitment = beverton_holt(1, 0.75)
    ),
    regexp = "`growth` must be a growth component spec"
  )
  expect_error(
    catch_at_age(population = logistic_maturity(3, 1)),
    regexp = "`population` must be a population component spec"
  )
  expect_error(
    catch_at_age(
      population = population(
        "stock",
        ages = 1:3,
        years = 2020:2022,
        growth = ewaa_growth(1:3, 1:3),
        maturity = logistic_maturity(3, 1),
        recruitment = beverton_holt(1, 0.75)
      ),
      observations = list("not an observation")
    ),
    regexp = "`observations` must contain only observation specs"
  )
})
